  import { getSumHours } from '@/api/hours.api';import DashboardTable from '@/components/Dashboard/DashboardDataTable/DashboardTable.vue';import { DateTime } from 'luxon';export default { name: 'SumTable', components: { DashboardTable }, data: () => ({ dialog: false, hours: [], dates: [], headers: [ { title: 'Name', key: 'name' }, { title: 'Time', key: 'time' }    ], }), async mounted () {
    this.$loading.show(); let now = new Date(); for (let i = 0; i < 7; i++) {
      const date = new Date(); date.setDate(now.getDate() - now.getDay() + i); now = date; this.dates.push(date)    }    const response = await getSumHours(DateTime.fromJSDate(this.dates[0]), DateTime.fromJSDate(this.dates.at(-1))); this.hours = response.data; this.$loading.hide()  }, methods: { async update () {
      this.$loading.show(); // reverses the array if the first element selected was the end if (this.dates[0] > this.dates.at(-1)) this.dates.reverse(); const response = await getSumHours(DateTime.fromJSDate(this.dates[0]), DateTime.fromJSDate(this.dates.at(-1))); this.hours = response.data; this.$loading.hide()    }, },};</script>
